functions.body:
local m="${1:-}" l=""
[ -n "$m" ] || return 1
l="$(printf '%s' "$m" | tr '[:upper:]' '[:lower:]')"
case "$l" in
  *image*|*imagen*|*img*|*vision*|*vqa*|*vit*|*clip*|*render* ) return 1 ;;
  *audio*|*speech*|*tts*|*wav2vec*|*whisper* ) return 1 ;;
  *embed*|*embedding*|*vector* ) return 1 ;;
  *multimodal* ) return 1 ;;
  *) return 0 ;;
esac

local cfg="${BASH4LLM_CONFIG_DIR%/}/config" key="" val="" line=""
[ -f "$cfg" ] || return 0
while IFS= read -r line || [ -n "$line" ]; do
  case "$line" in ''|\#*) continue ;; esac
  key="${line%%=*}"
  val="${line#*=}"
  case "$key" in
    MODEL) [ -n "$val" ] && MODEL="$val" ;;
    TEMPERATURE|TURE) [ -n "$val" ] && TURE="$val" ;;
    MAX_TOKENS) [ -n "$val" ] && MAX_TOKENS="$val" ;;
    FORMAT) [ -n "$val" ] && OUTPUT_MODE="$val" ;;
    THRESHOLD) [ -n "$val" ] && THRESHOLD="$val" ;;
  esac
done < "$cfg"
